import startImage from '../assets/startpage.png';

function MainPage() {
  return (
    <div className="relative min-h-screen flex flex-col items-center justify-between py-10 px-4 bg-white overflow-hidden">
      {/* 배경 이미지 깔기 */}
      <img
        src={startImage}
        alt="배경 이미지"
        className="absolute top-0 left-0 w-full h-full object-contain opacity-30 blur-sm -z-10"
      />

      {/* 상단 로고 */}
      <h1 className="text-3xl font-bold text-blue-600 mt-8">MainPage</h1>

      {/* 여기에 원하는 콘텐츠 추가 가능 */}
      <div className="space-y-4 mt-6 text-gray-800 font-medium">
        <p>이곳은 메인 페이지입니다.</p>
        <p>이 위에 기능을 올려갈 수 있어요!</p>
      </div>
    </div>
  );
}

export default MainPage;
